import{_ as t,o as n,c as s,a4 as e}from"./chunks/framework._in6GHBg.js";const d=JSON.parse('{"title":"作文结构模板","description":"","frontmatter":{},"headers":[],"relativePath":"chinese/tip-writing-structure.md","filePath":"chinese/tip-writing-structure.md"}'),l={name:"chinese/tip-writing-structure.md"};function p(o,a,i,r,c,h){return n(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="作文结构模板" tabindex="-1">作文结构模板 <a class="header-anchor" href="#作文结构模板" aria-label="Permalink to &quot;作文结构模板&quot;">​</a></h1><p><strong>从&quot;想到哪写到哪&quot;到&quot;结构清晰、逻辑严密&quot;——三种万能作文结构</strong></p><hr><h2 id="痛点" tabindex="-1">痛点 <a class="header-anchor" href="#痛点" aria-label="Permalink to &quot;痛点&quot;">​</a></h2><ul><li>写着写着不知道写到哪里了</li><li>文章结构混乱，东一句西一句</li><li>开头结尾都不错，中间一团糟</li><li>阅卷老师看不出文章层次</li></ul><hr><h2 id="模板一-并列式结构-适合素材丰富的题目" tabindex="-1">模板一：并列式结构（适合素材丰富的题目） <a class="header-anchor" href="#模板一-并列式结构-适合素材丰富的题目" aria-label="Permalink to &quot;模板一：并列式结构（适合素材丰富的题目）&quot;">​</a></h2><h3 id="结构图" tabindex="-1">结构图 <a class="header-anchor" href="#结构图" aria-label="Permalink to &quot;结构图&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开头（100字）：引出话题，亮明观点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主体1（200字）：分论点1 + 素材1 + 分析</span></span>
<span class="line"><span>主体2（200字）：分论点2 + 素材2 + 分析</span></span>
<span class="line"><span>主体3（200字）：分论点3 + 素材3 + 分析</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结尾（100字）：总结升华，回扣开头</span></span></code></pre></div><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p><strong>题目</strong>：坚持的力量</p><p><strong>开头</strong>：</p><blockquote><p>锲而舍之，朽木不折；锲而不舍，金石可镂。坚持，是通往成功的必由之路。</p></blockquote><p><strong>主体1</strong>：</p><ul><li>分论点：坚持需要坚定的信念</li><li>素材：司马迁忍辱负重，坚持完成《史记》</li><li>分析：正是因为有&quot;究天人之际&quot;的信念，他才能在绝境中坚持。</li></ul><p><strong>主体2</strong>：</p><ul><li>分论点：坚持需要科学的方法</li><li>素材：袁隆平数十年如一日研究杂交水稻</li><li>分析：他不仅坚持，更在实践中不断调整方法，终获成功。</li></ul><p><strong>主体3</strong>：</p><ul><li>分论点：坚持需要平和的心态</li><li>素材：黄旭华隐姓埋名三十年研制核潜艇</li><li>分析：不为名利，不计得失，这种淡然让坚持更持久。</li></ul><p><strong>结尾</strong>：</p><blockquote><p>坚持不是固执，而是信念、方法与心态的结合。唯有如此，方能行稳致远。</p></blockquote><h3 id="适用情况" tabindex="-1">适用情况 <a class="header-anchor" href="#适用情况" aria-label="Permalink to &quot;适用情况&quot;">​</a></h3><ul><li>有多个相关素材</li><li>题目涉及&quot;品质&quot;&quot;精神&quot;类（坚持、勇气、诚信等）</li></ul><hr><h2 id="模板二-层进式结构-适合有深度要求的题目" tabindex="-1">模板二：层进式结构（适合有深度要求的题目） <a class="header-anchor" href="#模板二-层进式结构-适合有深度要求的题目" aria-label="Permalink to &quot;模板二：层进式结构（适合有深度要求的题目）&quot;">​</a></h2><h3 id="结构图-1" tabindex="-1">结构图 <a class="header-anchor" href="#结构图-1" aria-label="Permalink to &quot;结构图&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开头（100字）：引出话题，提出问题</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主体1（150字）：是什么（解释概念/现象）</span></span>
<span class="line"><span>主体2（200字）：为什么（分析原因/意义）</span></span>
<span class="line"><span>主体3（250字）：怎么做（提出对策/方法）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结尾（100字）：总结升华</span></span></code></pre></div><h3 id="示例-1" tabindex="-1">示例 <a class="header-anchor" href="#示例-1" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p><strong>题目</strong>：生活的仪式感</p><p><strong>开头</strong>：</p><blockquote><p>有人认为仪式感是矫情，有人认为生活需要仪式感。仪式感究竟是什么？</p></blockquote><p><strong>主体1（是什么）</strong>：</p><blockquote><p>仪式感不是铺张浪费，而是对生活的一种态度。它是生日时的一碗长寿面，是节日里的一顿团圆饭，是平凡日子里的一点用心。</p></blockquote><p><strong>主体2（为什么）</strong>：</p><blockquote><p>为什么需要仪式感？首先，仪式感赋予生活意义，让平凡的日子有了特殊的记忆点。其次，仪式感连接情感，是家人、朋友之间情感的纽带。再者，仪式感对抗虚无，在快节奏的时代给我们停下来的理由。</p></blockquote><p><strong>主体3（怎么做）</strong>：</p><blockquote><p>培养仪式感，不需要 expensive 的花费，而需要用心的态度。可以是一个固定的家庭传统，可以是每天清晨的一杯咖啡，可以是睡前的一段阅读。重要的是，让某些时刻与其他时刻不同，让某些行为成为生活的锚点。</p></blockquote><p><strong>结尾</strong>：</p><blockquote><p>仪式感不是形式主义，而是对生活的热爱。在仪式感中，我们找到了生活的质感。</p></blockquote><h3 id="适用情况-1" tabindex="-1">适用情况 <a class="header-anchor" href="#适用情况-1" aria-label="Permalink to &quot;适用情况&quot;">​</a></h3><ul><li>涉及抽象概念（如仪式感、工匠精神、底线思维）</li><li>需要解释&quot;为什么&quot;的题目</li><li>适合展示思考深度</li></ul><hr><h2 id="模板三-对比式结构-适合有争议的话题" tabindex="-1">模板三：对比式结构（适合有争议的话题） <a class="header-anchor" href="#模板三-对比式结构-适合有争议的话题" aria-label="Permalink to &quot;模板三：对比式结构（适合有争议的话题）&quot;">​</a></h2><h3 id="结构图-2" tabindex="-1">结构图 <a class="header-anchor" href="#结构图-2" aria-label="Permalink to &quot;结构图&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开头（100字）：引出争议话题</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主体1（150字）：正面论述（A的好处/必要性）</span></span>
<span class="line"><span>主体2（150字）：反面论述（B的问题/局限）</span></span>
<span class="line"><span>主体3（250字）：辩证统一（A与B的平衡/结合）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结尾（100字）：总结升华</span></span></code></pre></div><h3 id="示例-2" tabindex="-1">示例 <a class="header-anchor" href="#示例-2" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p><strong>题目</strong>：快与慢</p><p><strong>开头</strong>：</p><blockquote><p>这是一个追求速度的时代，但越来越多的人开始呼唤&quot;慢生活&quot;。快与慢，究竟该如何选择？</p></blockquote><p><strong>主体1（快的必要）</strong>：</p><blockquote><p>快是时代的需要。科技发展日新月异，慢一步就可能落后。对个人而言，高效工作才能创造更多价值；对国家而言，快速发展才能在国际竞争中占据主动。</p></blockquote><p><strong>主体2（慢的价值）</strong>：</p><blockquote><p>但一味求快，也会出问题。身体亚健康、精神焦虑、关系淡漠，都是&quot;快&quot;的代价。慢下来，才能倾听内心的声音，才能品味生活的美好，才能建立深度的关系。</p></blockquote><p><strong>主体3（快与慢的平衡）</strong>：</p><blockquote><p>快与慢不是非此即彼。工作要快，生活要慢；创新要快，沉淀要慢；行动要快，思考要慢。关键是找到自己的节奏，在不同的情境下做出合适的选择。</p></blockquote><p><strong>结尾</strong>：</p><blockquote><p>快是效率，慢是智慧。真正的成熟，是懂得什么时候该快，什么时候该慢。</p></blockquote><h3 id="适用情况-2" tabindex="-1">适用情况 <a class="header-anchor" href="#适用情况-2" aria-label="Permalink to &quot;适用情况&quot;">​</a></h3><ul><li>有争议性的话题（如竞争与合作、传统与现代）</li><li>涉及两个对立概念</li><li>适合展示思辨能力</li></ul><hr><h2 id="结构选择指南" tabindex="-1">结构选择指南 <a class="header-anchor" href="#结构选择指南" aria-label="Permalink to &quot;结构选择指南&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">题目特点</th><th style="text-align:center;">推荐结构</th></tr></thead><tbody><tr><td style="text-align:center;">品质类（坚持、勇气、诚信）</td><td style="text-align:center;">并列式</td></tr><tr><td style="text-align:center;">抽象概念（仪式感、工匠精神）</td><td style="text-align:center;">层进式</td></tr><tr><td style="text-align:center;">争议话题（快与慢、竞争与合作）</td><td style="text-align:center;">对比式</td></tr><tr><td style="text-align:center;">多个素材可用</td><td style="text-align:center;">并列式</td></tr><tr><td style="text-align:center;">需要展示深度</td><td style="text-align:center;">层进式</td></tr></tbody></table><hr><h2 id="段落内部结构" tabindex="-1">段落内部结构 <a class="header-anchor" href="#段落内部结构" aria-label="Permalink to &quot;段落内部结构&quot;">​</a></h2><p>无论哪种结构，每个主体段都建议用：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>观点句（分论点）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>素材/例子（谁做了什么）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>分析（这个例子说明了什么）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>回扣（回到分论点）</span></span></code></pre></div><p><strong>示例</strong>：</p><blockquote><p>坚持需要坚定的信念。【观点】司马迁遭受宫刑，身处绝境，但他没有放弃，而是坚持完成了《史记》。【素材】正是因为有&quot;究天人之际，通古今之变&quot;的信念支撑，他才能在屈辱中坚持写作，最终留下&quot;史家之绝唱&quot;。【分析】可见，信念是坚持的内在动力。【回扣】</p></blockquote><hr><p><strong>文档编号</strong>: Chin-Tip-004<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,70)])])}const g=t(l,[["render",p]]);export{d as __pageData,g as default};
